let mocha = require('mocha');
let assert = require('assert');
let geo_point = require('geo-point');

describe('test geo_point', function() {
    it('test geo-point.GeoPoint.prototype.calculateDestination - basic functionality', function(done) {
        // Test basic destination calculation
        let startPoint = new geo_point.GeoPoint(40.7128, -74.0060); // New York City
        let distance = 1000; // 1000 meters
        let bearing = 90; // Due east

        let destination = startPoint.calculateDestination(distance, bearing);

        assert(destination instanceof geo_point.GeoPoint, 'Result should be a GeoPoint instance');
        assert(typeof destination.latitude === 'number', 'Latitude should be a number');
        assert(typeof destination.longitude === 'number', 'Longitude should be a number');

        // The destination should be east of the starting point
        assert(destination.longitude > startPoint.longitude, 'Longitude should increase when moving east');

        done();
    });

    it('test geo-point.GeoPoint.prototype.calculateDestination - zero distance', function(done) {
        let startPoint = new geo_point.GeoPoint(51.5074, -0.1278); // London
        let distance = 0;
        let bearing = 45;

        let destination = startPoint.calculateDestination(distance, bearing);

        // With zero distance, destination should be the same as start point
        assert.strictEqual(destination.latitude, startPoint.latitude, 'Latitude should remain unchanged with zero distance');
        assert.strictEqual(destination.longitude, startPoint.longitude, 'Longitude should remain unchanged with zero distance');

        done();
    });

    it('test geo-point.GeoPoint.prototype.calculateDestination - different bearings', function(done) {
        let startPoint = new geo_point.GeoPoint(0, 0); // Equator, Prime Meridian
        let distance = 1000;

        // Test north bearing (0 degrees)
        let northDestination = startPoint.calculateDestination(distance, 0);
        assert(northDestination.latitude > startPoint.latitude, 'Moving north should increase latitude');
        assert.strictEqual(northDestination.longitude, startPoint.longitude, 'Moving north should not change longitude');

        // Test south bearing (180 degrees)
        let southDestination = startPoint.calculateDestination(distance, 180);
        assert(southDestination.latitude < startPoint.latitude, 'Moving south should decrease latitude');
        assert.strictEqual(southDestination.longitude, startPoint.longitude, 'Moving south should not change longitude');

        // Test east bearing (90 degrees)
        let eastDestination = startPoint.calculateDestination(distance, 90);
        assert(eastDestination.longitude > startPoint.longitude, 'Moving east should increase longitude');
        assert.strictEqual(eastDestination.latitude, startPoint.latitude, 'Moving east should not change latitude');

        // Test west bearing (270 degrees)
        let westDestination = startPoint.calculateDestination(distance, 270);
        assert(westDestination.longitude < startPoint.longitude, 'Moving west should decrease longitude');
        assert.strictEqual(westDestination.latitude, startPoint.latitude, 'Moving west should not change latitude');

        done();
    });

    it('test geo-point.GeoPoint.prototype.calculateDestination - large distance', function(done) {
        let startPoint = new geo_point.GeoPoint(40.7128, -74.0060); // New York City
        let distance = 100000; // 100 km
        let bearing = 45; // Northeast

        let destination = startPoint.calculateDestination(distance, bearing);

        // Verify the result is still a valid geographic coordinate
        assert(destination.latitude >= -90 && destination.latitude <= 90, 'Latitude should be within valid range');
        assert(destination.longitude >= -180 && destination.longitude <= 180, 'Longitude should be within valid range');

        // With northeast bearing, both lat and lon should increase
        assert(destination.latitude > startPoint.latitude, 'Latitude should increase when moving northeast');
        assert(destination.longitude > startPoint.longitude, 'Longitude should increase when moving northeast');

        done();
    });

    it('test geo-point.GeoPoint.prototype.calculateDestination - edge case bearings', function(done) {
        let startPoint = new geo_point.GeoPoint(45.0, 0.0);
        let distance = 1000;

        // Test bearing 360 degrees (should be same as 0 degrees)
        let destination360 = startPoint.calculateDestination(distance, 360);
        let destination0 = startPoint.calculateDestination(distance, 0);

        assert.strictEqual(destination360.latitude, destination0.latitude, 'Bearing 360 should equal bearing 0');
        assert.strictEqual(destination360.longitude, destination0.longitude, 'Bearing 360 should equal bearing 0');

        done();
    });
});
